20	  const cellExists = (x: number, y: number): boolean => {
21	    return gridSet.has(serializeCell(x, y));
22	  };
23	
24	  // Count neighbors for each cell
25	  const countNeighbors = (x: number, y: number): number => {
26	    return NEIGHBOR_OFFSETS.filter(([dx, dy]) => cellExists(x + dx, y + dy)).length;
27	  };
28	
29	  // Collect all dead cells adjacent to live cells
