36	        if (!cellExists(nx, ny)) {
37	          deadCells.add(serializeCell(nx, ny));
38	        }
39	      }
40	    }
41	    return deadCells;
42	  };
43	
44	  // Rule 1 & 3: Live cells survive with 2-3 neighbors
45	  const survivingCells = grid.filter(([x, y]) => {
46	    const neighbors = countNeighbors(x, y);
47	    return neighbors >= 2 && neighbors <= 3;
48	  });
49	
50	  // Rule 4: Dead cells with exactly 3 neighbors become alive
51	  const deadCellsSet = collectDeadCellsAdjacentToLiveCells();
52	  const newCells: Array<[number, number]> = [];
53	  for (const cell of deadCellsSet) {
54	    const [x, y] = parseCell(cell);
55	    if (countNeighbors(x, y) === 3) {
56	      newCells.push([x, y]);
57	    }
58	  }
59	
60	  // Combine surviving cells and new cells
61	  const result = [...survivingCells, ...newCells];
